import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Mechanics Assessments","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/mechanics.md","filePath":"analytics/mechanics.md"}'),i={name:"analytics/mechanics.md"};function r(o,e,c,h,l,d){return s(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="mechanics-assessments" tabindex="-1">Mechanics Assessments <a class="header-anchor" href="#mechanics-assessments" aria-label="Permalink to &quot;Mechanics Assessments&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Mechanics assessments capture technique scores alongside statistics. Unlike stats which measure outcomes, mechanics assessments measure process — how a player executes the fundamental movements.</p><h2 id="scoring-scale" tabindex="-1">Scoring Scale <a class="header-anchor" href="#scoring-scale" aria-label="Permalink to &quot;Scoring Scale&quot;">​</a></h2><p>All integer mechanics elements use a 0–3 scale:</p><table tabindex="0"><thead><tr><th>Score</th><th>Meaning</th></tr></thead><tbody><tr><td>0</td><td>Not observed — element not present or not assessable</td></tr><tr><td>1</td><td>Needs significant work — consistent technical errors</td></tr><tr><td>2</td><td>Developing — partially correct, inconsistent execution</td></tr><tr><td>3</td><td>Correct — executed properly and consistently</td></tr></tbody></table><h2 id="four-mechanics-areas" tabindex="-1">Four Mechanics Areas <a class="header-anchor" href="#four-mechanics-areas" aria-label="Permalink to &quot;Four Mechanics Areas&quot;">​</a></h2><p><strong>Hitting Mechanics</strong> — 6 elements across setup, load, and swing phases: Load, Weight Transfer, Eye Tracking, Hip Rotation, Arm Path, Timing</p><p><strong>Pitching Mechanics</strong> — Baseball: 5 phases covering balance, stride, arm action, rotation, and finish. Softball: 5 phases specific to windmill delivery including arm circle, stride, hip drive, release, and follow-through</p><p><strong>Fielding Mechanics</strong> — 3 phases: Ready Position, Fielding the Ball, Transfer and Throw</p><p><strong>Baserunning Mechanics</strong> — 4 phases: Primary Lead, Secondary Lead and Read, Running Mechanics, Decision Making</p><h2 id="radar-chart" tabindex="-1">Radar Chart <a class="header-anchor" href="#radar-chart" aria-label="Permalink to &quot;Radar Chart&quot;">​</a></h2><p>The radar chart displays average scores for each phase. Larger shapes indicate better overall mechanics. Use this to quickly identify which phases need the most attention.</p><h2 id="trend-lines" tabindex="-1">Trend Lines <a class="header-anchor" href="#trend-lines" aria-label="Permalink to &quot;Trend Lines&quot;">​</a></h2><p>Trend charts show improvement or decline in each element over multiple assessment sessions. A minimum of 3 sessions is recommended before drawing conclusions from trends.</p><h2 id="when-to-use-mechanics-assessments" tabindex="-1">When to Use Mechanics Assessments <a class="header-anchor" href="#when-to-use-mechanics-assessments" aria-label="Permalink to &quot;When to Use Mechanics Assessments&quot;">​</a></h2><p>Mechanics assessments are conducted during <strong>Individual Practice</strong> sessions. They are not part of game scoring — use them during focused skill work sessions when you can observe technique closely.</p><h2 id="connection-to-training-plans" tabindex="-1">Connection to Training Plans <a class="header-anchor" href="#connection-to-training-plans" aria-label="Permalink to &quot;Connection to Training Plans&quot;">​</a></h2><p>Elements averaging below 2.0 trigger training suggestions automatically. These suggestions link to YouTube drill searches specific to the flagged element.</p>',19)])])}const p=a(i,[["render",r]]);export{u as __pageData,p as default};
